// ====================================================================================
// Context Handling in Query Handlers
// ====================================================================================

func TestComponent_QueryHandlers_UseContextWithTimeout(t *testing.T) {
	tests := []struct {
		name    string
		handler func(*Component, *mockNATSMsg)
		setup   func(*Component, context.Context)
	}{
		{
			name: "handleQueryOutgoing uses context",
			handler: func(c *Component, msg *mockNATSMsg) {
				c.handleQueryOutgoing(msg)
			},
			setup: func(c *Component, ctx context.Context) {
				c.UpdateOutgoingIndex(ctx, "entity", "target", "predicate")
			},
		},
		{
			name: "handleQueryIncoming uses context",
			handler: func(c *Component, msg *mockNATSMsg) {
				c.handleQueryIncoming(msg)
			},
			setup: func(c *Component, ctx context.Context) {
				c.UpdateIncomingIndex(ctx, "entity", "source", "predicate")
			},
		},
		{
			name: "handleQueryAlias uses context",
			handler: func(c *Component, msg *mockNATSMsg) {
				c.handleQueryAlias(msg)
			},
			setup: func(c *Component, ctx context.Context) {
				c.UpdateAliasIndex(ctx, "alias", "entity")
			},
		},
		{
			name: "handleQueryPredicate uses context",
			handler: func(c *Component, msg *mockNATSMsg) {
				c.handleQueryPredicate(msg)
			},
			setup: func(c *Component, ctx context.Context) {
				c.UpdatePredicateIndex(ctx, "entity", "predicate")
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			comp := createTestComponentWithMockKV(t)
			ctx := context.Background()

			// Setup test data
			tt.setup(comp, ctx)

			// Mock bucket to verify context usage
			contextUsed := false
			comp.outgoingBucket.(*mockKVBucket).getFunc = func(ctx context.Context, key string) (jetstream.KeyValueEntry, error) {
				contextUsed = true
				assert.NotNil(t, ctx, "context should be passed to KV operations")

				// Check for timeout
				deadline, hasDeadline := ctx.Deadline()
				if hasDeadline {
					assert.True(t, deadline.After(time.Now()), "context should have future deadline")
				}

				// Return data
				comp.outgoingBucket.(*mockKVBucket).mu.Lock()
				data := comp.outgoingBucket.(*mockKVBucket).data[key]
				comp.outgoingBucket.(*mockKVBucket).mu.Unlock()
				return &mockKVEntry{data: data}, nil
			}

			comp.incomingBucket.(*mockKVBucket).getFunc = comp.outgoingBucket.(*mockKVBucket).getFunc
			comp.aliasBucket.(*mockKVBucket).getFunc = comp.outgoingBucket.(*mockKVBucket).getFunc
			comp.predicateBucket.(*mockKVBucket).getFunc = comp.outgoingBucket.(*mockKVBucket).getFunc

			// Create request
			request := map[string]string{"entity_id": "entity", "alias": "alias", "predicate": "predicate"}
			requestJSON, _ := json.Marshal(request)

			msg := &mockNATSMsg{
				data: requestJSON,
			}

			// Handle query
			tt.handler(comp, msg)

			// Verify context was used (for non-capabilities handlers)
			if tt.name != "handleCapabilities uses context" {
				assert.True(t, contextUsed, "handler should use context for KV operations")
			}
		})
	}
}

