type mockNATSMsg struct {
	data     []byte
	response []byte
	subject  string
}

func (m *mockNATSMsg) Data() []byte {
	return m.data
}

func (m *mockNATSMsg) Subject() string {
	if m.subject == "" {
		return "test.subject"
	}
	return m.subject
}

func (m *mockNATSMsg) Reply() string {
	return "test.reply"
}

func (m *mockNATSMsg) Respond(data []byte) error {
	m.response = data
	return nil
}

func (m *mockNATSMsg) RespondMsg(msg *nats.Msg) error {
	m.response = msg.Data
	return nil
}

func (m *mockNATSMsg) Header() nats.Header {
	return nats.Header{}
}

func (m *mockNATSMsg) Ack() error {
	return nil
}

func (m *mockNATSMsg) AckSync() error {
	return nil
}

func (m *mockNATSMsg) DoubleAck(ctx context.Context) error {
	return nil
}

func (m *mockNATSMsg) InProgress() error {
	return nil
}

func (m *mockNATSMsg) Nak() error {
	return nil
}

func (m *mockNATSMsg) NakWithDelay(delay time.Duration) error {
	return nil
}

func (m *mockNATSMsg) Term() error {
	return nil
}

